export async function createOrReuseOpenPullRequest(
	input: {
		owner: string;
		repository: string;
		head: string;
		base: string;
		title: string;
		body: string;
	},
	env: RhapsodyGitHubEnv = loadRhapsodyGitHubEnv(),
	options?: {
		octokit?: OctokitPullRequestClient;
	},
): Promise<PullRequestSummary> {
	const existing = await findOpenPullRequestForHead({
		env,
		owner: input.owner,
		repository: input.repository,
		head: input.head,
		base: input.base,
		options,
	});

	if (existing) {
		return {
			reused: true,
			...existing,
		};
	}

	let created: Awaited<ReturnType<typeof createPullRequest>>;
	try {
		created = await createPullRequest({
			env,
			owner: input.owner,
			repository: input.repository,
			title: input.title,
			body: input.body,
			head: input.head,
			base: input.base,
			options,
		});
	} catch (error) {
		if (
			!(error instanceof GitHubPullRequestError) ||
			![409, 422].includes(error.status)
		) {
			throw error;
		}

		const racedExisting = await findOpenPullRequestForHead({
			env,
			owner: input.owner,
			repository: input.repository,
			head: input.head,
			base: input.base,
			options,
		});

		if (racedExisting) {
			return {
				reused: true,
				...racedExisting,
			};
		}

		throw error;
	}

	return {
		reused: false,
		...created,
	};
}

