+	const marker = `<!-- rhapsody:handoff-invalid:${selected?.number ?? "unknown"}:${pullRequest?.headSha ?? "unknown"} -->`;
+	const body = [
+		marker,
+		"Rhapsody could not accept the pull request handoff for this item.",
+		"",
+		`Reason: ${input.handoffVerification.reason}`,
+		"",
+		"Observed:",
