+		pullRequestUrl: pullRequest.htmlUrl,
+		baseBranch: pullRequest.baseRef,
+		headBranch: pullRequest.headRef,
+		headSha: pullRequest.headSha ?? null,
+		baseRepositoryOwner: pullRequest.baseRepositoryOwner ?? null,
